"""One-command installer: latest fixes + the new WEBSITE for this project.

Put this file inside your sahaayak-ai folder and run:  python fix.py
"""
import os, sys

FILES = {'config.py': '"""Central configuration. All tunables live here."""\nimport os\nfrom dotenv import load_dotenv\n\nload_dotenv()\n\n# --- Provider selection ---\n# "anthropic" (paid, best quality) or "gemini" (free tier: ~1,500 req/day, no card)\nLLM_PROVIDER = os.getenv("LLM_PROVIDER", "anthropic").lower()\n\n# --- API keys ---\nANTHROPIC_API_KEY = os.getenv("ANTHROPIC_API_KEY", "")\nGEMINI_API_KEY = os.getenv("GEMINI_API_KEY", "")\nGEMINI_MODEL = os.getenv("GEMINI_MODEL", "gemini-2.5-flash")\nTELEGRAM_BOT_TOKEN = os.getenv("TELEGRAM_BOT_TOKEN", "")\n\n# --- Models ---\n# Router/classifier: cheap + fast. Answer composition: higher quality.\nROUTER_MODEL = os.getenv("ROUTER_MODEL", "claude-haiku-4-5-20251001")\nANSWER_MODEL = os.getenv("ANSWER_MODEL", "claude-sonnet-4-6")\n\n# --- RAG ---\nCHROMA_DIR = os.getenv("CHROMA_DIR", os.path.join(os.path.dirname(__file__), "data", "chroma"))\nCOLLECTION_NAME = "seller_policies"\nCHUNK_SIZE = 900          # chars\nCHUNK_OVERLAP = 150       # chars\nTOP_K = 4\n# Chroma default embeddings return cosine distance; lower = closer.\n# If best hit is above this, we say "I couldn\'t find an official answer".\n# CALIBRATED (Jul 2026, eval/retrieval_eval.py): in-corpus top-hit distances\n# span 0.44-0.80; out-of-corpus 0.63-0.84. Distributions OVERLAP, so this\n# numeric gate only catches clearly-far queries; the NO_ANSWER prompt\n# contract in the retrieval agent is the primary hallucination brake for\n# the 0.6-0.8 overlap zone. Re-calibrate after any corpus change.\nMAX_DISTANCE = float(os.getenv("MAX_DISTANCE", "0.80"))\n\n# --- Behaviour ---\nMAX_HISTORY_TURNS = 8      # conversation turns kept per chat for context\nDAILY_MESSAGE_CAP = int(os.getenv("DAILY_MESSAGE_CAP", "60"))  # per user, cost guard\n\nSUPPORTED_MARKETPLACES = ["meesho", "amazon"]\n', 'agents/llm.py': '"""Single place that talks to the LLM provider.\n\nSupports two providers, selected by LLM_PROVIDER in .env:\n  - "anthropic" : paid API, best quality (two model tiers)\n  - "gemini"    : Google AI Studio free tier (~1,500 req/day on Flash, no card)\n\nEverything else in the codebase calls complete() / complete_vision() and\nnever knows which provider is behind it.\n"""\nfrom __future__ import annotations\n\nimport base64\nimport json\nimport re\n\nimport httpx\n\nimport config\n\n\ndef parse_json_block(text: str) -> dict:\n    """Extract the first JSON object from LLM output, tolerating prose,\n    markdown fences, and trailing commentary (Gemini is chattier than Claude)."""\n    text = text.strip()\n    m = re.search(r"\\{.*\\}", text, re.S)\n    if not m:\n        raise ValueError(f"no JSON object in: {text[:80]!r}")\n    return json.loads(m.group(0))\n\n# ---------------------------------------------------------------- anthropic\n\n_anthropic_client = None\n\n\ndef client():\n    """Anthropic SDK client (kept for backward compat; anthropic-only)."""\n    global _anthropic_client\n    if _anthropic_client is None:\n        import anthropic\n        _anthropic_client = anthropic.Anthropic(api_key=config.ANTHROPIC_API_KEY)\n    return _anthropic_client\n\n\ndef _anthropic_complete(system: str, messages: list[dict], model: str, max_tokens: int) -> str:\n    resp = client().messages.create(\n        model=model, max_tokens=max_tokens, system=system, messages=messages\n    )\n    return "".join(b.text for b in resp.content if b.type == "text")\n\n\n# ---------------------------------------------------------------- gemini\n\n_GEMINI_URL = "https://generativelanguage.googleapis.com/v1beta/models/{model}:generateContent"\n\n\ndef _to_gemini_contents(messages: list[dict]) -> list[dict]:\n    """Map Anthropic-style messages to Gemini contents (assistant -> model)."""\n    out = []\n    for m in messages:\n        role = "model" if m["role"] == "assistant" else "user"\n        content = m["content"]\n        parts = [{"text": content}] if isinstance(content, str) else content\n        out.append({"role": role, "parts": parts})\n    return out\n\n\n_resolved_model: str | None = None\n\n\ndef _resolve_gemini_model() -> str:\n    """Ask Google which models this key can use and pick the best Flash one.\n\n    Model names churn (2.0 retired, 2.5/3.x rollouts vary by account), so on a\n    404 we self-heal instead of hardcoding a name.\n    """\n    global _resolved_model\n    if _resolved_model:\n        return _resolved_model\n    r = httpx.get("https://generativelanguage.googleapis.com/v1beta/models",\n                  headers={"x-goog-api-key": config.GEMINI_API_KEY},\n                  params={"pageSize": 200}, timeout=30)\n    r.raise_for_status()\n    models = [m["name"].removeprefix("models/") for m in r.json().get("models", [])\n              if "generateContent" in m.get("supportedGenerationMethods", [])]\n    if not models:\n        raise RuntimeError("This Gemini key has no models supporting generateContent.")\n\n    def score(name: str) -> tuple:\n        n = name.lower()\n        return ("flash" in n,                      # prefer flash family (free tier)\n                "lite" not in n,                   # prefer full flash over lite\n                "preview" not in n and "exp" not in n,  # prefer stable\n                n)                                  # newest-ish by name sort\n    _resolved_model = sorted(models, key=score, reverse=True)[0]\n    return _resolved_model\n\n\ndef _gemini_call(system: str, contents: list[dict], max_tokens: int,\n                 _model: str | None = None, _no_thinking_cfg: bool = False) -> str:\n    model = _model or _resolved_model or config.GEMINI_MODEL\n    gen_cfg = {"maxOutputTokens": max(max_tokens, 1200)}  # headroom: thinking eats budget\n    if not _no_thinking_cfg:\n        # disable internal "thinking" on models that support the knob: faster,\n        # cheaper, and prevents reasoning fragments leaking into replies\n        gen_cfg["thinkingConfig"] = {"thinkingBudget": 0}\n    body = {\n        "systemInstruction": {"parts": [{"text": system}]},\n        "contents": contents,\n        "generationConfig": gen_cfg,\n    }\n    r = httpx.post(\n        _GEMINI_URL.format(model=model),\n        headers={"x-goog-api-key": config.GEMINI_API_KEY,\n                 "Content-Type": "application/json"},\n        json=body, timeout=60,\n    )\n    if r.status_code == 404 and _model is None:\n        # model name not available on this account -> discover and retry once\n        return _gemini_call(system, contents, max_tokens,\n                            _model=_resolve_gemini_model(), _no_thinking_cfg=_no_thinking_cfg)\n    if r.status_code == 400 and not _no_thinking_cfg:\n        # model doesn\'t accept thinkingConfig -> retry without it\n        return _gemini_call(system, contents, max_tokens,\n                            _model=model, _no_thinking_cfg=True)\n    r.raise_for_status()\n    data = r.json()\n    try:\n        parts = data["candidates"][0]["content"]["parts"]\n        text = "".join(p.get("text", "") for p in parts if not p.get("thought"))\n        if not text.strip():\n            raise KeyError("empty")\n        return text\n    except (KeyError, IndexError):\n        raise RuntimeError(f"Gemini returned no text (finishReason="\n                           f"{data.get(\'candidates\',[{}])[0].get(\'finishReason\',\'?\')})")\n\n\n# ---------------------------------------------------------------- public API\n\ndef complete(system: str, messages: list[dict], model: str, max_tokens: int = 1024) -> str:\n    if config.LLM_PROVIDER == "gemini":\n        return _gemini_call(system, _to_gemini_contents(messages), max_tokens)\n    return _anthropic_complete(system, messages, model, max_tokens)\n\n\ndef complete_vision(system: str, prompt: str, image_bytes: bytes,\n                    media_type: str = "image/jpeg", max_tokens: int = 300) -> str:\n    b64 = base64.standard_b64encode(image_bytes).decode()\n    if config.LLM_PROVIDER == "gemini":\n        contents = [{"role": "user", "parts": [\n            {"inline_data": {"mime_type": media_type, "data": b64}},\n            {"text": prompt},\n        ]}]\n        return _gemini_call(system, contents, max_tokens)\n    resp = client().messages.create(\n        model=config.ANSWER_MODEL, max_tokens=max_tokens, system=system,\n        messages=[{"role": "user", "content": [\n            {"type": "image", "source": {"type": "base64", "media_type": media_type, "data": b64}},\n            {"type": "text", "text": prompt},\n        ]}],\n    )\n    return "".join(b.text for b in resp.content if b.type == "text")\n', 'agents/vision.py': '"""Screenshot understanding (P1.2) — an INPUT ADAPTER, not a fourth agent.\n\nConverts a seller-panel screenshot into a short text description that then\nenters the normal five-stage flow like any typed message. Works with both\nproviders via llm.complete_vision().\n"""\nfrom __future__ import annotations\n\nfrom agents import llm\n\nIRRELEVANT = "IRRELEVANT_IMAGE"\n\nSYSTEM = """You read screenshots sent by small Indian e-commerce sellers (Meesho Supplier Panel, Amazon Seller Central, order/return/payment screens).\n\nExtract, in 1-3 short lines of plain text:\n- what screen/panel this is (if identifiable) and which marketplace\n- the exact error message, status, or issue shown\n- any order ID / SKU / claim ID / settlement ID visible\n\nHard rules:\n- If the image is NOT a seller-panel or e-commerce related screenshot, reply with exactly: IRRELEVANT_IMAGE\n- NEVER transcribe passwords, OTPs, CVVs, card numbers, or full bank account numbers, even if visible. Replace them with [hidden].\n- No commentary, no advice — extraction only. The support flow handles the rest."""\n\n\ndef extract_issue(image_bytes: bytes, media_type: str = "image/jpeg") -> str:\n    return llm.complete_vision(SYSTEM, "Extract the issue from this screenshot.",\n                               image_bytes, media_type).strip()\n', 'agents/action_agent.py': '"""Action Agent (P0.4).\n\nDrafts return-dispute claims, payment-hold emails, and listing-suppression appeals.\n\nSlot-filling contract:\n  - Each draft type declares mandatory fields.\n  - The agent extracts fields from the conversation; if any mandatory field is\n    missing it asks for ONE missing field at a time (never emits [PLACEHOLDER] drafts).\n  - Before drafting, it calls the retrieval agent to pull relevant policy language\n    so the draft cites policy (grounding).\n\nState is kept by the orchestrator and passed in as `pending` (dict) per chat.\n"""\nfrom __future__ import annotations\n\nimport json\n\nimport config\nfrom agents import llm, retrieval_agent\n\nDRAFT_TYPES = {\n    "return_dispute": {\n        "label": "Return / RTO dispute claim",\n        "fields": ["order_id", "issue_description"],\n        "optional": ["awb_number", "return_date", "product_name"],\n        "retrieval_hint": "return dispute wrong item used product claim window",\n    },\n    "payment_hold_email": {\n        "label": "Payment hold enquiry email",\n        "fields": ["issue_description"],\n        "optional": ["order_id", "hold_since", "amount"],\n        "retrieval_hint": "payment hold settlement cycle documents required",\n    },\n    "listing_appeal": {\n        "label": "Listing suppression appeal",\n        "fields": ["issue_description"],\n        "optional": ["sku", "asin_or_listing_id", "error_message"],\n        "retrieval_hint": "listing suppressed error appeal reinstate",\n    },\n}\n\nFIELD_QUESTIONS = {\n    "hinglish": {\n        "order_id": "Theek hai! Order ID kya hai?",\n        "issue_description": "Ek line mein batao — exact problem kya hai?",\n        "awb_number": "Return AWB number pata hai? (nahi pata to \'skip\' likho)",\n    },\n    "english": {\n        "order_id": "Got it — what\'s the order ID?",\n        "issue_description": "In one line, what exactly is the problem?",\n        "awb_number": "Do you have the return AWB number? (type \'skip\' if not)",\n    },\n}\n\nEXTRACT_SYSTEM = """Extract structured fields for an e-commerce seller support draft from the conversation.\nReturn ONLY a JSON object, no prose, no markdown fences. Schema:\n{"draft_type": one of ["return_dispute","payment_hold_email","listing_appeal"] or null,\n "marketplace": "meesho"|"amazon"|null,\n "fields": {<field_name>: <string value>}}\nOnly include fields explicitly stated by the seller. Never invent values.\nKnown field names: order_id, issue_description, awb_number, return_date, product_name, hold_since, amount, sku, asin_or_listing_id, error_message."""\n\nDRAFT_SYSTEM = """You draft marketplace seller-support submissions for small Indian sellers.\nWrite the draft in clear, polite, professional ENGLISH (marketplace support panels expect English),\nthen add one short line in the seller\'s language ({language}) telling them where to paste it.\n\nHard rules:\n- Use ONLY the field values provided. If a value is absent, do not mention it — NEVER write placeholders like [ORDER_ID].\n- Weave in the provided policy excerpts (quote the policy point briefly, cite doc + section) to strengthen the case.\n- Structure: greeting → issue summary with facts → policy basis → clear request → sign-off.\n- Keep under 200 words. No emotional language; factual and firm.\n- End with: "— Draft by SahaayakAI. Please review details before submitting.\\""""\n\n\ndef extract(conversation_text: str) -> dict:\n    """One LLM call: figure out draft type + fields mentioned so far."""\n    raw = llm.complete(\n        system=EXTRACT_SYSTEM,\n        messages=[{"role": "user", "content": conversation_text}],\n        model=config.ROUTER_MODEL,\n        max_tokens=300,\n    )\n    try:\n        return llm.parse_json_block(raw)\n    except (ValueError, json.JSONDecodeError):\n        return {"draft_type": None, "marketplace": None, "fields": {}}\n\n\ndef next_missing_field(draft_type: str, fields: dict) -> str | None:\n    for f in DRAFT_TYPES[draft_type]["fields"]:\n        if not fields.get(f):\n            return f\n    return None\n\n\ndef ask_for_field(field: str, language: str) -> str:\n    table = FIELD_QUESTIONS.get(language, FIELD_QUESTIONS["english"])\n    return table.get(field, f"Please share: {field.replace(\'_\', \' \')}")\n\n\ndef make_draft(draft_type: str, marketplace: str | None, fields: dict, language: str) -> str:\n    spec = DRAFT_TYPES[draft_type]\n    rag = retrieval_agent.answer(\n        question=f"{spec[\'retrieval_hint\']} {fields.get(\'issue_description\',\'\')}",\n        marketplace=marketplace,\n        language="english",\n    )\n    policy_block = rag["answer"] if rag["found"] else "(no specific policy excerpt found — draft on facts only)"\n    payload = {\n        "draft_type": spec["label"],\n        "marketplace": marketplace or "unspecified",\n        "fields": {k: v for k, v in fields.items() if v},\n        "policy_excerpts": policy_block,\n    }\n    return llm.complete(\n        system=DRAFT_SYSTEM.format(language=language),\n        messages=[{"role": "user", "content": json.dumps(payload, ensure_ascii=False)}],\n        model=config.ANSWER_MODEL,\n        max_tokens=700,\n    ).strip()\n', 'agents/orchestrator.py': '"""Orchestrator (P0.3 + P0.5).\n\nResponsibilities:\n  1. Safety pre-checks (credential detection) — before anything else.\n  2. Intent classification: policy_query | action_request | other.\n  3. Language detection: hinglish | english.\n  4. Conversation state per chat (history + pending action slots + rate limit).\n  5. Route to retrieval agent or action agent; compose final reply.\n\nClassification uses a cheap LLM call with a deterministic keyword fallback, so the\nbot still routes sensibly if the router call fails.\n"""\nfrom __future__ import annotations\n\nimport json\nimport re\nimport time\nfrom dataclasses import dataclass, field\n\nimport config\nfrom agents import llm, retrieval_agent, action_agent, telemetry, persistence\n\n# ---------------------------------------------------------------- state\n\n@dataclass\nclass ChatState:\n    history: list[dict] = field(default_factory=list)   # [{"role","content"}]\n    pending_action: dict | None = None                  # {"draft_type","marketplace","fields"}\n    awaiting_field: str | None = None                   # slot the bot just asked for\n    language: str = "hinglish"\n    marketplace: str | None = None\n    msg_timestamps: list[float] = field(default_factory=list)\n\n\n_chats: dict[str, ChatState] = {}\n\n\ndef state_for(chat_id: str) -> ChatState:\n    if chat_id not in _chats:\n        saved = persistence.load_state(chat_id)\n        _chats[chat_id] = ChatState(**saved) if saved else ChatState()\n    return _chats[chat_id]\n\n\ndef _persist(chat_id: str, st: ChatState) -> None:\n    persistence.save_state(chat_id, {\n        "history": st.history,\n        "pending_action": st.pending_action,\n        "awaiting_field": st.awaiting_field,\n        "language": st.language,\n        "marketplace": st.marketplace,\n        "msg_timestamps": st.msg_timestamps,\n    })\n\n\n# ---------------------------------------------------------------- safety (P0.5)\n\nCREDENTIAL_PATTERNS = [\n    re.compile(r"\\botp\\b.{0,12}\\d{4,8}", re.I),\n    re.compile(r"\\bpassword\\b\\s*[:\\-]?\\s*\\S+", re.I),\n    re.compile(r"\\bcvv\\b\\s*[:\\-]?\\s*\\d{3,4}", re.I),\n    re.compile(r"\\b\\d{9,18}\\b.{0,20}\\bifsc\\b|\\bifsc\\b.{0,20}\\b\\d{9,18}\\b", re.I),\n]\n\nCREDENTIAL_WARNING = {\n    "hinglish": (\n        "⚠️ Ruko! Aapne abhi password/OTP/bank detail jaisi cheez bheji hai. "\n        "Main ye kabhi store ya use nahi karta, aur aapko bhi kisi bot ya insaan ko "\n        "ye kabhi nahi dena chahiye — official app ke alawa kahin nahi. "\n        "Message dobara bina us detail ke bhejo. 🙏"\n    ),\n    "english": (\n        "⚠️ Hold on — that message looks like it contains a password/OTP/bank detail. "\n        "I never store or use these, and you should never share them with any bot or person "\n        "outside the official app. Please resend your message without that detail."\n    ),\n}\n\nUNSUPPORTED_MARKETPLACES = ("flipkart", "myntra", "ajio", "snapdeal", "ebay", "etsy", "nykaa")\n\nUNSUPPORTED_MP_MSG = {\n    "hinglish": ("Abhi main sirf *Meesho* aur *Amazon India* ke seller issues cover karta hoon. "\n                 "Flipkart/Myntra jaise platforms ka official answer mere paas nahi hai — "\n                 "unke apne seller support se poochhna sahi rahega. 🙏"),\n    "english": ("Right now I only cover *Meesho* and *Amazon India* seller issues. "\n                "For other platforms, please check their own seller support."),\n}\n\nINTRO = (\n    "Namaste! 🙏 Main *SahaayakAI* hoon — Meesho aur Amazon India sellers ka support assistant.\\n\\n"\n    "Aap mujhse ye sab poochh sakte ho:\\n"\n    "1️⃣ \\"Customer ne 15 din baad return kiya, accept karna padega?\\"\\n"\n    "2️⃣ \\"Mera payment hold pe hai, kya karun?\\"\\n"\n    "3️⃣ \\"Return claim ka draft bana do, order ID XXXXX\\"\\n\\n"\n    "⚠️ Note: main sirf *draft* banata hoon — submit aap khud review karke karoge. "\n    "Kabhi bhi mujhe (ya kisi ko bhi) password/OTP mat bhejna."\n)\n\nOFF_TOPIC = {\n    "hinglish": "Main sirf Meesho/Amazon seller issues mein madad karta hoon — returns, payments, listings, claims. Us bare mein poochho! 🙂",\n    "english": "I only help with Meesho/Amazon seller issues — returns, payments, listings, claims. Ask me about those! 🙂",\n}\n\nRATE_LIMIT_MSG = {\n    "hinglish": "Aaj ke liye message limit ho gayi. Kal phir baat karte hain! 🙏",\n    "english": "You\'ve hit today\'s message limit. Let\'s continue tomorrow! 🙏",\n}\n\n# ---------------------------------------------------------------- routing (P0.3)\n\nROUTER_SYSTEM = """Classify a message from an Indian e-commerce seller. Return ONLY JSON:\n{"intent": "policy_query" | "action_request" | "other",\n "language": "hinglish" | "english",\n "marketplace": "meesho" | "amazon" | null}\n\nDefinitions:\n- policy_query: asking what a rule/policy/process/deadline is, why something happened, what to do.\n- action_request: asking you to DRAFT/WRITE something (claim, appeal, email, application) or continuing to provide details for a draft in progress.\n- other: greetings, thanks, abuse, off-topic (weather, jokes, personal chat).\n- language "hinglish" if the message uses any romanized Hindi; "english" if fully English. Devanagari also => "hinglish".\n- marketplace only if stated or clearly implied in THIS message or the provided context; else null.\nContext (may be empty): {context}"""\n\nACTION_KEYWORDS = ("draft", "bana do", "banao", "likh do", "likho", "write", "email bhejna", "claim file", "apply")\nPOLICY_KEYWORDS = ("policy", "kya karun", "kaise", "kyun", "why", "how", "kitne din", "deadline", "hold", "return", "payment", "listing", "claim", "penalty", "rto")\nGREETING_KEYWORDS = ("hi", "hello", "namaste", "hey", "thanks", "thank you", "shukriya",\n                     "dhanyavad", "good morning", "good evening", "bye", "ok bye", "kaise ho",\n                     "kya haal", "tum kaun", "who are you", "joke", "mausam", "weather")\n\n\ndef classify_heuristic(text: str) -> dict:\n    """Deterministic fallback — also used by the eval as a baseline."""\n    t = text.lower().strip()\n    lang = "english" if not re.search(\n        r"\\b(hai|karo|kya|nahi|mera|bana|kaise|kyun|karna|wala|bhai|din|paisa|hua|gaya|do)\\b", t\n    ) and not re.search(r"[\\u0900-\\u097F]", t) else "hinglish"\n    mp = "meesho" if "meesho" in t else ("amazon" if "amazon" in t else None)\n    if any(t == k or t.startswith(k + " ") or t.endswith(" " + k) or t == k.rstrip() for k in GREETING_KEYWORDS) or len(t) < 4:\n        intent = "other"\n    elif any(k in t for k in ACTION_KEYWORDS):\n        intent = "action_request"\n    elif any(k in t for k in POLICY_KEYWORDS):\n        intent = "policy_query"\n    else:\n        intent = "policy_query"  # default: try to help\n    return {"intent": intent, "language": lang, "marketplace": mp}\n\n\ndef classify(text: str, ctx: ChatState) -> dict:\n    context = ""\n    if ctx.pending_action:\n        context = f"A draft ({ctx.pending_action[\'draft_type\']}) is in progress; seller may be answering a field question."\n    if ctx.history:\n        context += " Last topic: " + ctx.history[-1]["content"][:120]\n    try:\n        raw = llm.complete(\n            system=ROUTER_SYSTEM.format(context=context or "none"),\n            messages=[{"role": "user", "content": text}],\n            model=config.ROUTER_MODEL,\n            max_tokens=120,\n        )\n        out = llm.parse_json_block(raw)\n        assert out.get("intent") in ("policy_query", "action_request", "other")\n        return out\n    except Exception:\n        return classify_heuristic(text)\n\n\n# ---------------------------------------------------------------- main entry\n\ndef handle_message(chat_id: str, text: str) -> str:\n    st = state_for(chat_id)\n    text = text.strip()\n\n    t0 = time.time()\n\n    def _log(reply: str, intent: str, grounded: bool | None = None,\n             n_citations: int = 0, event: str | None = None) -> str:\n        telemetry.log_turn(\n            chat_id, text, reply, intent=intent, language=st.language,\n            marketplace=st.marketplace, latency_ms=int((time.time() - t0) * 1000),\n            grounded=grounded, n_citations=n_citations, event=event,\n        )\n        _persist(chat_id, st)\n        return reply\n\n    # rate limit (cost guard)\n    now = time.time()\n    st.msg_timestamps = [t for t in st.msg_timestamps if now - t < 86400]\n    if len(st.msg_timestamps) >= config.DAILY_MESSAGE_CAP:\n        return _log(RATE_LIMIT_MSG.get(st.language, RATE_LIMIT_MSG["english"]),\n                    intent="blocked", event="rate_limit")\n    st.msg_timestamps.append(now)\n\n    if text.lower() in ("/start", "start"):\n        return _log(INTRO, intent="other", event="start")\n\n    # P0.5 — credential guard runs before anything else\n    if any(p.search(text) for p in CREDENTIAL_PATTERNS):\n        return _log(CREDENTIAL_WARNING.get(st.language, CREDENTIAL_WARNING["english"]),\n                    intent="blocked", event="credential_guard")\n\n    # Scope guard: query about a marketplace we don\'t cover (deterministic;\n    # embeddings can\'t reliably refuse these — calibration showed overlap)\n    tl = text.lower()\n    if any(m in tl for m in UNSUPPORTED_MARKETPLACES) and not any(m in tl for m in config.SUPPORTED_MARKETPLACES):\n        return _log(UNSUPPORTED_MP_MSG.get(st.language, UNSUPPORTED_MP_MSG["english"]),\n                    intent="other", event="unsupported_marketplace")\n\n    cls = classify(text, st)\n    st.language = cls.get("language") or st.language\n    st.marketplace = cls.get("marketplace") or st.marketplace\n\n    st.history.append({"role": "user", "content": text})\n    st.history = st.history[-config.MAX_HISTORY_TURNS * 2:]\n\n    grounded: bool | None = None\n    n_citations = 0\n    route = cls["intent"]  # the effective route actually taken (logged for metrics)\n\n    # --- the bot just asked for a specific field: this message IS the answer,\n    #     no matter what the classifier thinks it looks like\n    if st.pending_action and st.awaiting_field:\n        pa = st.pending_action\n        pa["fields"][st.awaiting_field] = None if text.lower().strip() == "skip" else text\n        st.awaiting_field = None\n        reply = _continue_action(st, text, already_extracted=True)\n        route = "action_request"\n    # --- a draft is in progress: treat message as slot answer unless clearly a new topic\n    elif st.pending_action and cls["intent"] != "policy_query":\n        reply = _continue_action(st, text)\n        route = "action_request"\n    elif cls["intent"] == "action_request":\n        reply = _start_or_continue_action(st, text)\n    elif cls["intent"] == "policy_query":\n        result = retrieval_agent.answer(\n            text, marketplace=st.marketplace, language=st.language,\n            history=st.history[:-1][-4:],\n        )\n        reply = result["answer"]\n        grounded = result["found"]\n        n_citations = len(result.get("citations", []))\n    else:\n        reply = OFF_TOPIC.get(st.language, OFF_TOPIC["english"])\n\n    st.history.append({"role": "assistant", "content": reply})\n    return _log(reply, intent=route, grounded=grounded, n_citations=n_citations)\n\n\n# ---------------------------------------------------------------- action flow\n\ndef _start_or_continue_action(st: ChatState, text: str) -> str:\n    convo = "\\n".join(f"{m[\'role\']}: {m[\'content\']}" for m in st.history[-8:])\n    ext = action_agent.extract(convo)\n    dtype = ext.get("draft_type")\n    if not dtype or dtype not in action_agent.DRAFT_TYPES:\n        options = "\\n".join(f"• {v[\'label\']}" for v in action_agent.DRAFT_TYPES.values())\n        if st.language == "hinglish":\n            return f"Zaroor! Kaunsa draft chahiye?\\n{options}\\n\\nSaath mein problem ek line mein batao."\n        return f"Sure! Which draft do you need?\\n{options}\\n\\nAlso tell me the problem in one line."\n    st.pending_action = {\n        "draft_type": dtype,\n        "marketplace": ext.get("marketplace") or st.marketplace,\n        "fields": ext.get("fields", {}),\n    }\n    return _continue_action(st, text, already_extracted=True)\n\n\ndef _continue_action(st: ChatState, text: str, already_extracted: bool = False) -> str:\n    pa = st.pending_action\n    if not already_extracted:\n        convo = "\\n".join(f"{m[\'role\']}: {m[\'content\']}" for m in st.history[-8:])\n        ext = action_agent.extract(convo)\n        for k, v in (ext.get("fields") or {}).items():\n            pa["fields"].setdefault(k, v)\n        pa["marketplace"] = pa.get("marketplace") or ext.get("marketplace") or st.marketplace\n\n    missing = action_agent.next_missing_field(pa["draft_type"], pa["fields"])\n    if missing:\n        st.awaiting_field = missing\n        return action_agent.ask_for_field(missing, st.language)\n\n    draft = action_agent.make_draft(pa["draft_type"], pa["marketplace"], pa["fields"], st.language)\n    st.pending_action = None\n    st.awaiting_field = None\n    return draft\n', 'webapp.py': '"""SahaayakAI web app — the same agents, on a website.\n\nThe orchestrator is channel-agnostic by design; this is channel #2 (after\nTelegram). Serves the landing page with a LIVE chat wired to the real bot.\n\nRun:   python webapp.py        ->  http://localhost:8000\nNeeds: pip install flask  (and the usual .env + ingested corpus)\n"""\nfrom __future__ import annotations\n\nimport logging\nimport re\n\nfrom flask import Flask, jsonify, request, send_from_directory\n\nfrom agents import orchestrator\n\nlogging.basicConfig(format="%(asctime)s %(levelname)s %(name)s: %(message)s", level=logging.INFO)\nlog = logging.getLogger("sahaayak.web")\n\napp = Flask(__name__, static_folder="web", static_url_path="")\n\n\n@app.get("/")\ndef index():\n    return send_from_directory("web", "index.html")\n\n\n@app.post("/api/chat")\ndef chat():\n    data = request.get_json(force=True, silent=True) or {}\n    text = (data.get("message") or "").strip()[:2000]\n    raw_id = re.sub(r"[^a-zA-Z0-9_-]", "", str(data.get("chat_id") or ""))[:40]\n    chat_id = f"web-{raw_id or \'anon\'}"\n    if not text:\n        return jsonify({"reply": "Kuch likho to sahi! 🙂"})\n    log.info("chat=%s in=%r", chat_id, text[:80])\n    try:\n        reply = orchestrator.handle_message(chat_id, text)\n    except Exception:\n        log.exception("web handler failed")\n        reply = "Kuch technical problem aa gayi 😅 — thodi der mein dobara try karo."\n    return jsonify({"reply": reply})\n\n\n@app.get("/health")\ndef health():\n    return {"ok": True}\n\n\nif __name__ == "__main__":\n    import os\n    port = int(os.getenv("PORT", "8000"))\n    print(f"\\n  SahaayakAI web app -> open http://localhost:{port} in your browser\\n")\n    app.run(host="0.0.0.0", port=port, debug=False)\n', 'web/index.html': '<!DOCTYPE html>\n<html lang="en">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>SahaayakAI — Seller ka apna support assistant</title>\n<meta name="description" content="Meesho & Amazon India sellers ke policy sawaalon ke jawab — Hinglish mein, citation ke saath. Live try karo, abhi.">\n<link rel="preconnect" href="https://fonts.googleapis.com">\n<link href="https://fonts.googleapis.com/css2?family=Baloo+2:wght@500;600;700;800&family=Karla:wght@400;500;700&family=IBM+Plex+Mono:wght@400;500&display=swap" rel="stylesheet">\n<style>\n:root{\n  --ink:#14225A; --ink-2:#1E2F73; --paper:#F7F6F0; --line:#E4E1D4;\n  --marigold:#EFA13A; --marigold-deep:#D98A1F; --alert:#D9482B;\n  --white:#FFFFFF; --ink-soft:#3D4A85; --radius:14px;\n}\n*{margin:0;padding:0;box-sizing:border-box}\nhtml{scroll-behavior:smooth}\nbody{font-family:\'Karla\',sans-serif;color:var(--ink);background:var(--paper);line-height:1.6}\na{color:inherit}\n.wrap{max-width:1080px;margin:0 auto;padding:0 24px}\nnav{background:var(--ink);color:var(--white);position:sticky;top:0;z-index:50}\n.nav-in{display:flex;align-items:center;justify-content:space-between;padding:14px 24px;max-width:1080px;margin:0 auto}\n.logo{font-family:\'Baloo 2\',sans-serif;font-weight:800;font-size:1.35rem}\n.logo .dot{color:var(--marigold)}\n.btn{display:inline-block;font-family:\'Baloo 2\',sans-serif;font-weight:700;text-decoration:none;\n  background:var(--marigold);color:var(--ink);padding:10px 22px;border-radius:999px;border:none;cursor:pointer;\n  transition:transform .15s ease, background .15s ease;font-size:1rem}\n.btn:hover{background:#F6B558;transform:translateY(-1px)}\n.btn:focus-visible{outline:3px solid var(--white);outline-offset:2px}\n.btn.big{font-size:1.12rem;padding:14px 32px}\n\nheader{background:var(--ink);color:var(--white);overflow:hidden}\n.hero{display:grid;grid-template-columns:1fr 1fr;gap:44px;align-items:center;padding:64px 24px 80px;max-width:1080px;margin:0 auto}\n.eyebrow{font-family:\'IBM Plex Mono\',monospace;font-size:.8rem;letter-spacing:.14em;text-transform:uppercase;color:var(--marigold);margin-bottom:16px}\nh1{font-family:\'Baloo 2\',sans-serif;font-weight:800;font-size:clamp(2rem,4.4vw,3.2rem);line-height:1.12;margin-bottom:18px}\nh1 em{font-style:normal;color:var(--marigold)}\n.hero p.sub{font-size:1.1rem;color:#C9D0EE;max-width:44ch;margin-bottom:26px}\n.live-dot{display:inline-flex;align-items:center;gap:8px;font-family:\'IBM Plex Mono\',monospace;font-size:.78rem;color:#9fe6b0}\n.live-dot i{width:8px;height:8px;border-radius:50%;background:#39d46a;animation:pulse 1.6s infinite}\n@keyframes pulse{0%,100%{opacity:.4}50%{opacity:1}}\n@media (prefers-reduced-motion: reduce){.live-dot i{animation:none}}\n\n/* live chat */\n.phone{background:#0E1840;border:1px solid #2A3B87;border-radius:26px;padding:16px 14px;max-width:420px;width:100%;\n  box-shadow:0 24px 60px rgba(0,0,0,.35);margin-left:auto;display:flex;flex-direction:column}\n.phone-top{display:flex;align-items:center;gap:10px;padding:4px 6px 12px;border-bottom:1px solid #23336F}\n.avatar{width:34px;height:34px;border-radius:50%;background:var(--marigold);color:var(--ink);\n  display:flex;align-items:center;justify-content:center;font-family:\'Baloo 2\',sans-serif;font-weight:800}\n.phone-top .name{font-weight:700;font-size:.95rem}\n.phone-top .status{font-size:.72rem;color:#8FA0DB}\n.chat{padding:14px 4px;display:flex;flex-direction:column;gap:10px;height:380px;overflow-y:auto;scroll-behavior:smooth}\n.msg{max-width:88%;padding:10px 13px;border-radius:14px;font-size:.86rem;line-height:1.55;white-space:pre-wrap;word-wrap:break-word}\n.msg.seller{align-self:flex-end;background:var(--marigold);color:var(--ink);border-bottom-right-radius:4px;font-weight:500}\n.msg.bot{align-self:flex-start;background:#FFFFFF;color:var(--ink);border-bottom-left-radius:4px}\n.typing{align-self:flex-start;display:flex;gap:4px;padding:12px 14px;background:#FFF;border-radius:14px;border-bottom-left-radius:4px}\n.typing i{width:6px;height:6px;border-radius:50%;background:#9AA6D8;animation:blink 1s infinite}\n.typing i:nth-child(2){animation-delay:.18s}.typing i:nth-child(3){animation-delay:.36s}\n@keyframes blink{0%,70%,100%{opacity:.25}35%{opacity:1}}\n.chips{display:flex;flex-wrap:wrap;gap:8px;padding:8px 4px 0}\n.chip-btn{font-family:\'Karla\',sans-serif;font-size:.76rem;background:#1B2C6E;color:#C9D0EE;border:1px solid #33449A;\n  border-radius:999px;padding:6px 12px;cursor:pointer}\n.chip-btn:hover{background:#24377F;color:#fff}\n.composer{display:flex;gap:8px;padding-top:12px}\n.composer input{flex:1;background:#1B2C6E;border:1px solid #33449A;border-radius:999px;color:#fff;\n  padding:11px 16px;font-family:\'Karla\',sans-serif;font-size:.9rem;outline:none}\n.composer input::placeholder{color:#8FA0DB}\n.composer input:focus{border-color:var(--marigold)}\n.composer button{background:var(--marigold);border:none;border-radius:50%;width:44px;height:44px;cursor:pointer;\n  font-size:1.1rem;color:var(--ink);font-weight:700}\n.composer button:disabled{opacity:.5;cursor:default}\n\nsection{padding:72px 0}\n.ruled{background:repeating-linear-gradient(to bottom, var(--paper), var(--paper) 34px, var(--line) 34px, var(--line) 35px)}\nh2{font-family:\'Baloo 2\',sans-serif;font-weight:800;font-size:clamp(1.6rem,3vw,2.1rem);margin-bottom:10px}\n.sec-sub{color:#5A628C;max-width:56ch;margin-bottom:40px}\n.kicker{font-family:\'IBM Plex Mono\',monospace;font-size:.78rem;letter-spacing:.14em;text-transform:uppercase;color:var(--marigold-deep);display:block;margin-bottom:10px}\n.flow{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}\n.step{background:var(--white);border:1px solid var(--line);border-radius:var(--radius);padding:26px 22px;position:relative}\n.step .n{font-family:\'IBM Plex Mono\',monospace;color:var(--marigold-deep);font-size:.8rem;letter-spacing:.1em;margin-bottom:10px;display:block}\n.step h3{font-family:\'Baloo 2\',sans-serif;font-weight:700;font-size:1.12rem;margin-bottom:8px}\n.step p{font-size:.94rem;color:#45507F}\n.step:not(:last-child)::after{content:"→";position:absolute;right:-19px;top:50%;transform:translateY(-50%);color:var(--marigold-deep);font-size:1.3rem;font-weight:700}\n.trust{display:grid;grid-template-columns:repeat(3,1fr);gap:22px}\n.t-card{background:var(--ink);color:var(--white);border-radius:var(--radius);padding:26px 22px}\n.t-card h3{font-family:\'Baloo 2\',sans-serif;font-size:1.08rem;margin-bottom:8px;color:var(--marigold)}\n.t-card p{font-size:.93rem;color:#C9D0EE}\n.t-card .mono{display:block;margin-top:14px;font-size:.72rem;background:#0E1840;border-radius:8px;padding:10px;color:#AEB8E4;font-family:\'IBM Plex Mono\',monospace}\n.cta-band{background:var(--ink);color:var(--white);text-align:center;border-radius:20px;padding:52px 28px;margin:0 24px}\n.cta-band h2{color:var(--white)}\n.cta-band p{color:#C9D0EE;margin-bottom:26px;max-width:560px;margin-left:auto;margin-right:auto}\nfooter{padding:34px 24px 46px;text-align:center;color:#6A7199;font-size:.85rem}\nfooter a{color:var(--ink);font-weight:700;text-decoration:none;border-bottom:2px solid var(--marigold)}\n.disclaimer{margin-top:8px;font-size:.78rem}\n@media (max-width:880px){\n  .hero{grid-template-columns:1fr;padding-top:44px}\n  .phone{margin:0 auto}\n  .flow,.trust{grid-template-columns:1fr}\n  .step:not(:last-child)::after{content:"↓";right:auto;left:50%;top:auto;bottom:-24px;transform:translateX(-50%)}\n}\n</style>\n</head>\n<body>\n\n<nav>\n  <div class="nav-in">\n    <div class="logo">Sahaayak<span class="dot">AI</span></div>\n    <a class="btn" href="#top">Try it live</a>\n  </div>\n</nav>\n\n<header id="top">\n  <div class="hero">\n    <div>\n      <div class="eyebrow">Meesho · Amazon India · Live demo</div>\n      <h1>Seller support docs mein <em>ghanton dhundhna</em> band karo.</h1>\n      <p class="sub">Returns, payment holds, listing errors — policy ka seedha jawab Hinglish mein,\n        official source ke saath. Aur claim ka ready draft, copy-paste ke liye.</p>\n      <div class="live-dot"><i></i> Ye demo asli hai — poochh ke dekho →</div>\n    </div>\n\n    <!-- LIVE chat: wired to the real agents via /api/chat -->\n    <div class="phone">\n      <div class="phone-top">\n        <div class="avatar">S</div>\n        <div>\n          <div class="name">SahaayakAI</div>\n          <div class="status">online · 3 agents behind this chat</div>\n        </div>\n      </div>\n      <div class="chat" id="chat">\n        <div class="msg bot">Namaste! 🙏 Main SahaayakAI hoon — Meesho aur Amazon India sellers ka assistant. Policy ka sawaal poochho, ya claim ka draft banwao. Hinglish ya English — dono chalega.</div>\n      </div>\n      <div class="chips" id="chips">\n        <button class="chip-btn">customer ne used product return kiya, kya karun?</button>\n        <button class="chip-btn">mera payment hold pe kyu hai?</button>\n        <button class="chip-btn">Draft a return claim, order ID MSH123</button>\n      </div>\n      <form class="composer" id="composer">\n        <input id="inp" type="text" placeholder="Apna sawaal likho…" autocomplete="off" maxlength="1000">\n        <button type="submit" id="send" aria-label="Send">➤</button>\n      </form>\n    </div>\n  </div>\n</header>\n\n<section class="ruled" id="how">\n  <div class="wrap">\n    <span class="kicker">Kaise kaam karta hai</span>\n    <h2>Ek message, teen AI agents.</h2>\n    <p class="sec-sub">Har message pehle route hota hai, phir sahi agent handle karta hai — isliye jawab fast bhi hai aur bharosemand bhi.</p>\n    <div class="flow">\n      <div class="step">\n        <span class="n">STEP 1 — ROUTER</span>\n        <h3>Samajhta hai kya chahiye</h3>\n        <p>Aapka message padhkar decide karta hai: policy ka sawaal hai, draft banwana hai, ya kuch aur. Hinglish ho ya English — dono chalega.</p>\n      </div>\n      <div class="step">\n        <span class="n">STEP 2 — RETRIEVAL</span>\n        <h3>Official policy se jawab</h3>\n        <p>Meesho aur Amazon India ke seller policy documents mein se exact section dhundhta hai. Har jawab ke saath source ka naam — guess kabhi nahi.</p>\n      </div>\n      <div class="step">\n        <span class="n">STEP 3 — ACTION</span>\n        <h3>Ready draft banata hai</h3>\n        <p>Return dispute, payment-hold email, listing appeal — order details poochhkar complete draft deta hai jo seedha panel mein paste ho sake.</p>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section>\n  <div class="wrap">\n    <span class="kicker">Bharosa</span>\n    <h2>Galat advice = paisa loss. Isliye teen pakke rules.</h2>\n    <p class="sec-sub">Chhote seller ke liye ek galat deadline bhi mehenga padta hai — bot isko seriously leta hai.</p>\n    <div class="trust">\n      <div class="t-card">\n        <h3>Har jawab ke saath source</h3>\n        <p>Policy ka har point official document ke section se aata hai — aap khud verify kar sakte ho, ya marketplace support ko dikha sakte ho.</p>\n        <span class="mono">📄 Source: Meesho Returns Policy / Compensation</span>\n      </div>\n      <div class="t-card">\n        <h3>Pata nahi = saaf bolega</h3>\n        <p>Agar official docs mein jawab nahi mila, to bot guess nahi karega — seedha bolega "official answer nahi mila" aur sahi jagah point karega.</p>\n        <span class="mono">bot&gt; Mujhe iska official policy answer nahi mila 🙏</span>\n      </div>\n      <div class="t-card">\n        <h3>Password/OTP kabhi nahi</h3>\n        <p>Bot kabhi password, OTP ya bank detail nahi maangta — aur agar aap bhej do, to warn karta hai. Drafts sirf suggestions hain; submit aap khud karte ho.</p>\n        <span class="mono">⚠️ Kabhi kisi ko OTP mat bhejna — bot ko bhi nahi</span>\n      </div>\n    </div>\n  </div>\n</section>\n\n<section class="ruled">\n  <div class="cta-band">\n    <h2>Telegram pe bhi available.</h2>\n    <p>Yahi assistant aapke phone pe — screenshots bhejo, feedback buttons, sab kuch. Pilot join karo, free.</p>\n    <a class="btn big" href="https://t.me/YOUR_BOT_USERNAME">Telegram pe shuru karo →</a>\n  </div>\n</section>\n\n<footer>\n  <div>Open source project — <a href="https://github.com/YOUR_USERNAME/sahaayak-ai">code on GitHub</a></div>\n  <div class="disclaimer">SahaayakAI is an independent tool, not affiliated with Meesho or Amazon. Drafts are suggestions — always review before submitting.</div>\n</footer>\n\n<script>\n(function(){\n  var chat = document.getElementById(\'chat\');\n  var form = document.getElementById(\'composer\');\n  var inp = document.getElementById(\'inp\');\n  var send = document.getElementById(\'send\');\n  var chips = document.getElementById(\'chips\');\n\n  var chatId = localStorage.getItem(\'sahaayak_chat_id\');\n  if (!chatId) {\n    chatId = \'u\' + Math.random().toString(36).slice(2, 12);\n    localStorage.setItem(\'sahaayak_chat_id\', chatId);\n  }\n\n  function esc(s){ var d=document.createElement(\'div\'); d.textContent=s; return d.innerHTML; }\n  function fmt(s){\n    return esc(s).replace(/\\*\\*(.+?)\\*\\*/g, \'<b>$1</b>\').replace(/\\*(.+?)\\*/g, \'<i>$1</i>\');\n  }\n  function add(role, text){\n    var m = document.createElement(\'div\');\n    m.className = \'msg \' + role;\n    m.innerHTML = fmt(text);\n    chat.appendChild(m);\n    chat.scrollTop = chat.scrollHeight;\n    return m;\n  }\n  function typing(on){\n    var t = document.getElementById(\'t-ind\');\n    if (on && !t){\n      t = document.createElement(\'div\'); t.id=\'t-ind\'; t.className=\'typing\';\n      t.innerHTML=\'<i></i><i></i><i></i>\'; chat.appendChild(t); chat.scrollTop = chat.scrollHeight;\n    } else if (!on && t){ t.remove(); }\n  }\n\n  function ask(text){\n    if (!text) return;\n    add(\'seller\', text);\n    if (chips) { chips.remove(); chips = null; }\n    inp.value = \'\'; send.disabled = true; typing(true);\n    fetch(\'/api/chat\', {\n      method: \'POST\',\n      headers: {\'Content-Type\': \'application/json\'},\n      body: JSON.stringify({chat_id: chatId, message: text})\n    })\n    .then(function(r){ return r.json(); })\n    .then(function(d){ typing(false); add(\'bot\', d.reply || \'…\'); })\n    .catch(function(){ typing(false); add(\'bot\', \'Server se connect nahi ho paya 😅 — check karo ki webapp.py chal raha hai.\'); })\n    .finally(function(){ send.disabled = false; inp.focus(); });\n  }\n\n  form.addEventListener(\'submit\', function(e){ e.preventDefault(); ask(inp.value.trim()); });\n  document.querySelectorAll(\'.chip-btn\').forEach(function(b){\n    b.addEventListener(\'click\', function(){ ask(b.textContent); });\n  });\n})();\n</script>\n</body>\n</html>\n', 'requirements.txt': 'anthropic>=0.40.0\nchromadb>=0.5.0\npython-telegram-bot>=21.0\npython-dotenv>=1.0.0\nflask>=3.0\ngunicorn>=21.0\n', 'render.yaml': '# Render blueprint: deploy SahaayakAI website free.\n# In Render: New + -> Blueprint -> pick this repo -> it reads this file.\nservices:\n  - type: web\n    name: sahaayak-ai\n    runtime: python\n    plan: free\n    buildCommand: pip install -r requirements.txt && python -m rag.ingest --reset\n    startCommand: gunicorn webapp:app --bind 0.0.0.0:$PORT --workers 1 --threads 4 --timeout 120\n    envVars:\n      - key: LLM_PROVIDER\n        value: gemini\n      - key: GEMINI_API_KEY\n        sync: false          # you paste this in the Render dashboard, never in git\n      - key: PYTHON_VERSION\n        value: 3.12.3\n', '.github/workflows/ci.yml': 'name: CI\non:\n  push:\n    branches: [main]\n  pull_request:\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - uses: actions/setup-python@v5\n        with:\n          python-version: "3.12"\n      - name: Install dependencies\n        run: pip install -r requirements.txt pytest\n      - name: Unit tests (27 tests, no API keys needed)\n        run: pytest tests/ -q\n      - name: Routing eval — heuristic baseline must stay >= 90%\n        run: python eval/run_eval.py --heuristic\n      - name: Retrieval eval — grounding hit@4 >= 90% + refusal gates\n        run: |\n          python -m rag.ingest --reset\n          python eval/retrieval_eval.py\n', 'README.md': '# 🛍️ SahaayakAI — AI Support Agent for Indian E-commerce Sellers\n\n![Python](https://img.shields.io/badge/python-3.10%2B-blue)\n![CI](https://github.com/YOUR_USERNAME/sahaayak-ai/actions/workflows/ci.yml/badge.svg)\n![License](https://img.shields.io/badge/license-MIT-green)\n![Status](https://img.shields.io/badge/status-pilot-orange)\n\n**A multi-agent Telegram bot that answers Meesho/Amazon India seller-policy\nquestions in Hinglish — with citations — and drafts ready-to-submit return\nclaims, payment-hold emails, and listing appeals.**\n\nSmall sellers lose real money to missed claim deadlines, fraudulent returns,\nand payment holds — because the answers are buried in dense, English-only\nhelp docs. SahaayakAI compresses "1–2 hours of searching" into one chat message.\n\n```\nSeller:  customer ne 15 din baad return kiya, accept karna padega kya?\nBot:     Nahi, zaroori nahi. Customer return window delivery se 7 din ki hoti\n         hai... Aap dispute raise kar sakte ho. Chaaho to main draft bana doon?\n         📄 Source: Meesho Returns & Return Claims Policy / Customer Return Window\n```\n\n## ✨ Features\n\n- 🔍 **Grounded policy answers (RAG)** — retrieves from indexed official policy\n  docs and answers *only* from them. Every answer cites its source; if\n  confidence is low it honestly says "not found" instead of guessing.\n- ✍️ **Claim & email drafting** — slot-filling flow collects order ID, issue,\n  AWB one question at a time, then generates a copy-paste-ready draft that\n  quotes the relevant policy. Never emits `[PLACEHOLDER]` junk.\n- 🧠 **Multi-agent architecture** — a cheap/fast model routes intent\n  (policy question vs. draft request vs. chit-chat); a stronger model composes\n  answers. Conservative retrieval + productive drafting, cleanly separated.\n- 🗣️ **Hinglish-first** — detects and mirrors the seller\'s language.\n- 🛡️ **Safety guardrails** — detects and refuses passwords/OTPs/bank details\n  before any processing; never auto-submits anything; daily message cap.\n- 💾 **Restart-proof** — SQLite persistence: mid-draft conversations survive\n  redeploys.\n- 📊 **Built-in observability** — privacy-safe JSONL telemetry (hashed chat\n  IDs), a one-command metrics report, groundedness audit sampler, a 50-query\n  routing eval (96% on the no-LLM fallback alone), and 👍/👎 feedback buttons.\n\n## 🏗️ Architecture\n\n```\nTelegram → main.py → ORCHESTRATOR (routing · state · guardrails)\n                        ├─→ RETRIEVAL AGENT ──→ ChromaDB (policy corpus)\n                        │     answers only from retrieved chunks, cites sources\n                        └─→ ACTION AGENT\n                              slot-filling → policy-grounded draft\n```\n\n| Component | Choice | Why |\n|---|---|---|\n| Channel | Telegram (long polling) | free token, no webhook/server needed |\n| Vector DB | ChromaDB, local embeddings | zero extra API keys, runs anywhere |\n| LLM | Anthropic API (2 tiers) | cheap router + quality composer |\n| Framework | ~700 lines plain Python | debuggable, no framework magic |\n| State | SQLite | pilot-scale persistence, one file |\n\n## 🚀 Quick Start\n\n```bash\ngit clone <this-repo> && cd seller-support-agent\npip install -r requirements.txt\ncp .env.example .env            # add TELEGRAM_BOT_TOKEN + ANTHROPIC_API_KEY\npython -m rag.ingest --reset    # index the policy corpus\npython cli.py                   # try it in your terminal\npython main.py                  # go live on Telegram\n```\n\nDocker: `docker compose up -d --build`. Full runbook in [SETUP.md](SETUP.md). Deep-dive design: [docs/ARCHITECTURE.md](docs/ARCHITECTURE.md). Build it yourself: [docs/BUILD_GUIDE.md](docs/BUILD_GUIDE.md).\n\n> ⚠️ **Before real sellers use it:** verify every `[VERIFY]` marker in\n> `corpus/` against the live Supplier Panel / Seller Central. The\n> no-hallucination guarantee is only as strong as the corpus.\n\n## 🧪 Quality Gates\n\n```bash\npytest tests/ -q                       # 19 tests, no API key needed\npython eval/run_eval.py                # routing accuracy (target >=90%)\npython eval/metrics_report.py --audit  # PRD metrics + groundedness sample\n```\n\n## 🗺️ Roadmap\n\n- ✅ v0.1 — RAG core, orchestrator, action agent, Telegram, telemetry, evals\n- 🔜 WhatsApp channel (Business API) · screenshot understanding (vision) ·\n  claim-deadline reminders\n- 🔮 More marketplaces (Flipkart) · regional languages (Marathi, Tamil) ·\n  seller memory\n\n## 📁 Structure\n\n```\nagents/        orchestrator, retrieval agent, action agent, telemetry, persistence\nrag/           ingestion (chunking) + ChromaDB wrapper\ncorpus/        marketplace policy docs (markdown, section-structured)\neval/          routing eval set, eval runner, metrics/audit report\ntests/         19 pytest tests for the deterministic core\n```\n\n## 🤝 Contributing & Disclaimer\n\nPRs welcome — especially corpus improvements with official sources. This tool\ndrafts suggestions; sellers must review before submitting. Not affiliated with\nMeesho or Amazon. MIT licensed.\n'}

def find_project(start):
    candidates = [start, os.path.join(start, "sahaayak-ai"), os.path.dirname(start)]
    for c in candidates:
        if os.path.isfile(os.path.join(c, "cli.py")) and os.path.isdir(os.path.join(c, "agents")):
            return c
    return None

here = os.path.dirname(os.path.abspath(__file__))
root = find_project(here) or find_project(os.getcwd())
if not root:
    sys.exit("Could not find the project (cli.py + agents/). Put fix.py inside the sahaayak-ai folder and run again.")

for rel, content in FILES.items():
    path = os.path.join(root, rel.replace("/", os.sep))
    os.makedirs(os.path.dirname(path) or root, exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"  wrote {path}")

sys.path.insert(0, root)
